from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time
import random

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "app_requests_total",
    "Total number of HTTP requests",
    ["method", "endpoint", "http_status"],
)

REQUEST_LATENCY = Histogram(
    "app_request_latency_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10),
)

IN_PROGRESS = Gauge(
    "app_requests_in_progress",
    "Number of requests currently in progress",
    ["method", "endpoint"],
)

BUSINESS_EVENTS = Counter(
    "app_business_events_total",
    "Total number of business events processed",
    ["event_type"],
)

BUSINESS_METRIC_GAUGE = Gauge(
    "app_business_active_users",
    "Current number of active users",
)

BUSINESS_VALUE_HISTOGRAM = Histogram(
    "app_business_order_value",
    "Distribution of simulated order values",
    buckets=(5, 10, 25, 50, 100, 250, 500, 1000),
)


@app.before_request
def before_request():
    endpoint = request.endpoint or "unknown"
    IN_PROGRESS.labels(request.method, endpoint).inc()
    request._start_time = time.perf_counter()


@app.after_request
def after_request(response):
    endpoint = request.endpoint or "unknown"
    latency = time.perf_counter() - getattr(request, "_start_time", time.perf_counter())
    REQUEST_COUNT.labels(request.method, endpoint, str(response.status_code)).inc()
    REQUEST_LATENCY.labels(request.method, endpoint).observe(latency)
    IN_PROGRESS.labels(request.method, endpoint).dec()
    return response


@app.route("/")
def index():
    BUSINESS_EVENTS.labels("page_view").inc()
    return jsonify(message="Hello from Flask with Prometheus metrics")


@app.route("/business/checkout", methods=["POST"])
def checkout():
    order_value = random.uniform(10, 500)
    BUSINESS_EVENTS.labels("checkout").inc()
    BUSINESS_VALUE_HISTOGRAM.observe(order_value)
    return jsonify(status="processed", order_value=round(order_value, 2))


@app.route("/business/active-users")
def active_users():
    active = random.randint(0, 1000)
    BUSINESS_METRIC_GAUGE.set(active)
